{% assign active_days = calendar.size %}
{% assign theme_mode = trmnl.plugin_settings.custom_fields_values.theme | default: theme | default: 'dark' %}
{% if theme_mode == 'light' %}
  {% assign page_bg = '#f6f1e8' %}
  {% assign primary_text = '#141414' %}
  {% assign accent_text = '#6f6558' %}
  {% assign panel_bg = '#fffdfa' %}
  {% assign rail_bg = '#ece3d7' %}
  {% assign border_color = '#d5ccbf' %}
{% else %}
  {% assign page_bg = '#111111' %}
  {% assign primary_text = '#fffdf8' %}
  {% assign accent_text = '#d8c9a2' %}
  {% assign panel_bg = '#1a1a1a' %}
  {% assign rail_bg = '#24211d' %}
  {% assign border_color = '#3b352d' %}
{% endif %}

<div class="layout layout--col h--full w--full" style="padding: 12px 14px 10px; background:{{ page_bg }}; color:{{ primary_text }};">
  <div style="display:flex; justify-content:space-between; align-items:end; border-bottom:2px solid {{ primary_text }}; padding-bottom:6px; margin-bottom:8px;">
    <div style="font-size:22px; line-height:0.95; letter-spacing:-0.04em; font-weight:900; color:{{ primary_text }};">Upcoming</div>
    <div style="font-size:9px; line-height:1; text-transform:uppercase; letter-spacing:0.12em; color:{{ accent_text }}; font-weight:800;">{{ active_days }} days</div>
  </div>

  <div style="display:grid; grid-template-columns:repeat(2, minmax(0, 1fr)); gap:10px; flex:1; align-content:start;">
    {% for day in calendar limit:2 %}
    <div style="display:grid; grid-template-columns:58px minmax(0, 1fr); background:{{ panel_bg }}; border:1px solid {{ border_color }}; border-radius:14px; overflow:hidden; min-height:96px;">
      <div style="padding:10px 8px; background:{{ rail_bg }}; border-right:1px solid {{ border_color }}; display:flex; flex-direction:column; justify-content:space-between;">
        {% assign day_number = day.date | slice: 0, 2 %}
        {% assign day_label = day.date | remove_first: day_number | strip %}
        <div>
          <div style="font-size:24px; line-height:0.86; font-weight:900; letter-spacing:-0.05em; color:{{ primary_text }};">{{ day_number }}</div>
          <div style="font-size:8px; line-height:1.1; text-transform:uppercase; letter-spacing:0.08em; color:{{ accent_text }}; font-weight:800;">{{ day_label }}</div>
        </div>
      </div>
      <div style="padding:10px 10px; display:flex; flex-direction:column; justify-content:center; gap:6px;">
        {% for event in day.events limit:2 %}
        <div style="display:grid; grid-template-columns:4px minmax(0, 1fr); gap:7px; align-items:start;">
          <div style="width:4px; min-height:28px; border-radius:99px; background:{{ event.source_color | default: 'black' }};"></div>
          <div style="display:flex; flex-direction:column; gap:2px; min-width:0;">
            <div style="font-size:13px; line-height:0.96; font-weight:900; letter-spacing:-0.03em; color:{{ primary_text }};">{{ event.summary }}</div>
            {% if event.start %}
            <div style="font-size:8px; line-height:1; text-transform:uppercase; letter-spacing:0.12em; color:{{ accent_text }}; font-weight:800;">{{ event.start }}</div>
            {% endif %}
          </div>
        </div>
        {% endfor %}
        {% if day.hidden_events and day.hidden_events > 0 %}
        <div style="font-size:8px; line-height:1; text-transform:uppercase; letter-spacing:0.12em; color:{{ accent_text }}; font-weight:900;">+{{ day.hidden_events }} more</div>
        {% endif %}
      </div>
    </div>
    {% endfor %}
  </div>
</div>

quad:
{% assign first_day = calendar.first %}
{% assign theme_mode = trmnl.plugin_settings.custom_fields_values.theme | default: theme | default: 'dark' %}
{% if theme_mode == 'light' %}
  {% assign page_bg = '#f6f1e8' %}
  {% assign primary_text = '#141414' %}
  {% assign accent_text = '#6f6558' %}
{% else %}
  {% assign page_bg = '#111111' %}
  {% assign primary_text = '#fffdf8' %}
  {% assign accent_text = '#d8c9a2' %}
{% endif %}

<div class="layout layout--col h--full w--full" style="padding: 10px 10px 8px; background:{{ page_bg }}; color:{{ primary_text }};">
  <div style="font-size:16px; line-height:1; letter-spacing:-0.04em; font-weight:900; color:{{ primary_text }}; padding-bottom:6px; border-bottom:1px solid {{ primary_text }}; margin-bottom:8px;">Upcoming</div>

  {% if first_day %}
  <div style="display:grid; grid-template-columns:48px minmax(0, 1fr); gap:8px; align-items:start; flex:1;">
    <div style="padding-top:2px;">
      {% assign day_number = first_day.date | slice: 0, 2 %}
      {% assign day_label = first_day.date | remove_first: day_number | strip %}
      <div style="font-size:24px; line-height:0.86; font-weight:900; letter-spacing:-0.05em; color:{{ primary_text }};">{{ day_number }}</div>
      <div style="font-size:8px; line-height:1.05; text-transform:uppercase; letter-spacing:0.08em; color:{{ accent_text }}; font-weight:800;">{{ day_label }}</div>
    </div>
    <div style="display:flex; flex-direction:column; gap:6px; min-width:0;">
      {% for event in first_day.events limit:2 %}
      <div style="display:grid; grid-template-columns:4px minmax(0, 1fr); gap:7px; align-items:start;">
        <div style="width:4px; min-height:26px; border-radius:99px; background:{{ event.source_color | default: 'black' }};"></div>
        <div style="display:flex; flex-direction:column; gap:2px; min-width:0;">
          <div style="font-size:12px; line-height:0.95; font-weight:900; letter-spacing:-0.03em; color:{{ primary_text }};">{{ event.summary }}</div>
          {% if event.start %}
          <div style="font-size:8px; line-height:1; text-transform:uppercase; letter-spacing:0.12em; color:{{ accent_text }}; font-weight:800;">{{ event.start }}</div>
          {% endif %}
        </div>
      </div>
      {% endfor %}
      {% if first_day.hidden_events and first_day.hidden_events > 0 %}
      <div style="font-size:8px; line-height:1; text-transform:uppercase; letter-spacing:0.12em; color:{{ accent_text }}; font-weight:900;">+{{ first_day.hidden_events }} more</div>
      {% endif %}
    </div>
  </div>
  {% endif %}
</div>
